local cjson = require "cjson"

-- Simple XML parser that handles entity references
-- This avoids external dependencies while being suitable for OpenResty

local XmlParser = {}
XmlParser.__index = XmlParser

-- Entity reference mapping
local entity_map = {
    ["&amp;"]  = "&",
    ["&lt;"]   = "<",
    ["&gt;"]   = ">",
    ["&quot;"] = '"',
    ["&apos;"] = "'",
}

-- Resolve standard XML entity references and numeric character references
local function resolve_entities(text)
    if not text then
        return text
    end
    -- Replace named entities
    text = text:gsub("(&%w+;)", function(entity)
        return entity_map[entity] or entity
    end)
    -- Replace decimal numeric character references &#123;
    text = text:gsub("&#(%d+);", function(dec)
        return string.char(tonumber(dec))
    end)
    -- Replace hex numeric character references &#x1A;
    text = text:gsub("&#x(%x+);", function(hex)
        return string.char(tonumber(hex, 16))
    end)
    return text
end

-- Trim whitespace
local function trim(s)
    if not s then return nil end
    return s:match("^%s*(.-)%s*$")
end

-- Parse XML attributes from a tag string
local function parse_attributes(attr_string)
    local attrs = {}
    if not attr_string or attr_string == "" then
        return attrs
    end
    for name, value in attr_string:gmatch('([%w_:%-]+)%s*=%s*"(.-)"') do
        attrs[name] = resolve_entities(value)
    end
    for name, value in attr_string:gmatch("([%w_:%-]+)%s*=%s*'(.-)'") do
        attrs[name] = resolve_entities(value)
    end
    return attrs
end

-- Parse XML string into a Lua table structure
function XmlParser.parse(xml_string)
    if not xml_string or xml_string == "" then
        return nil, "Empty XML input"
    end

    -- Remove XML declaration
    xml_string = xml_string:gsub("<%?xml.-?%?>", "")
    -- Remove comments
    xml_string = xml_string:gsub("<!%-%-.-%--%>", "")
    -- Remove CDATA sections but keep content
    xml_string = xml_string:gsub("<!%[CDATA%[(.-)%]%]>", "%1")

    local stack = {}
    local root = { _children = {}, _type = "root" }
    local current = root

    -- Iterate through tags and text
    local pos = 1
    while pos <= #xml_string do
        local tag_start = xml_string:find("<", pos)

        if not tag_start then
            -- Remaining text
            local text = trim(xml_string:sub(pos))
            if text and text ~= "" then
                current._text = (current._text or "") .. resolve_entities(text)
            end
            break
        end

        -- Text before this tag
        if tag_start > pos then
            local text = xml_string:sub(pos, tag_start - 1)
            local trimmed = trim(text)
            if trimmed and trimmed ~= "" then
                current._text = (current._text or "") .. resolve_entities(text)
            end
        end

        local tag_end = xml_string:find(">", tag_start)
        if not tag_end then
            return nil, "Malformed XML: unclosed tag at position " .. tag_start
        end

        local tag_content = xml_string:sub(tag_start + 1, tag_end - 1)

        if tag_content:sub(1, 1) == "/" then
            -- Closing tag
            local tag_name = trim(tag_content:sub(2))
            if not tag_name or tag_name == "" then
                return nil, "Malformed XML: empty closing tag"
            end
            -- Validate that closing tag matches current element
            if current._name ~= tag_name then
                return nil, string.format(
                    "Malformed XML: closing tag </%s> does not match opening tag <%s>",
                    tag_name, current._name or "?"
                )
            end
            -- Trim text content
            if current._text then
                current._text = trim(current._text)
            end
            current = table.remove(stack)
            if not current then
                return nil, "Malformed XML: extra closing tag </" .. tag_name .. ">"
            end
        elseif tag_content:sub(-1) == "/" then
            -- Self-closing tag
            tag_content = tag_content:sub(1, -2)
            local tag_name, attr_string = tag_content:match("^([%w_:%-]+)%s*(.*)")
            if not tag_name then
                return nil, "Malformed XML: invalid self-closing tag"
            end
            local node = {
                _name = tag_name,
                _attrs = parse_attributes(attr_string),
                _children = {},
                _type = "element",
            }
            table.insert(current._children, node)
            -- Also store as named child for easy access
            if current[tag_name] then
                -- Multiple elements with same name -> convert to array
                if type(current[tag_name]) ~= "table" or current[tag_name]._type then
                    current[tag_name] = { current[tag_name] }
                end
                table.insert(current[tag_name], node)
            else
                current[tag_name] = node
            end
        else
            -- Opening tag
            local tag_name, attr_string = tag_content:match("^([%w_:%-]+)%s*(.*)")
            if not tag_name then
                return nil, "Malformed XML: invalid opening tag"
            end
            local node = {
                _name = tag_name,
                _attrs = parse_attributes(attr_string),
                _children = {},
                _type = "element",
            }
            table.insert(current._children, node)
            -- Store as named child
            if current[tag_name] then
                if type(current[tag_name]) ~= "table" or current[tag_name]._type then
                    current[tag_name] = { current[tag_name] }
                end
                table.insert(current[tag_name], node)
            else
                current[tag_name] = node
            end
            table.insert(stack, current)
            current = node
        end

        pos = tag_end + 1
    end

    if #stack > 0 then
        return nil, "Malformed XML: unclosed tags remain"
    end

    -- Return the first child as the root element
    if #root._children > 0 then
        return root._children[1], nil
    end

    return nil, "No root element found"
end

-- Utility: get text content of a node
function XmlParser.get_text(node)
    if not node then return nil end
    return node._text
end

-- Utility: get attribute value
function XmlParser.get_attr(node, attr_name)
    if not node or not node._attrs then return nil end
    return node._attrs[attr_name]
end

-- Utility: find a child element by name (supports namespace prefix)
function XmlParser.find_child(node, name)
    if not node or not node._children then return nil end
    for _, child in ipairs(node._children) do
        if child._name == name then
            return child
        end
        -- Also try matching without namespace prefix
        local local_name = child._name:match(":(.+)$")
        if local_name == name then
            return child
        end
    end
    return nil
end

-- Utility: find all children with given name
function XmlParser.find_children(node, name)
    local results = {}
    if not node or not node._children then return results end
    for _, child in ipairs(node._children) do
        if child._name == name then
            table.insert(results, child)
        else
            local local_name = child._name:match(":(.+)$")
            if local_name == name then
                table.insert(results, child)
            end
        end
    end
    return results
end

-- Utility: recursively find a descendant element by name
function XmlParser.find_descendant(node, name)
    if not node or not node._children then return nil end
    for _, child in ipairs(node._children) do
        if child._name == name then
            return child
        end
        local local_name = child._name:match(":(.+)$")
        if local_name == name then
            return child
        end
        local found = XmlParser.find_descendant(child, name)
        if found then return found end
    end
    return nil
end

-- Utility: extract all text values from node into a flat table
function XmlParser.extract_fields(node)
    local fields = {}
    if not node or not node._children then return fields end
    for _, child in ipairs(node._children) do
        local name = child._name
        -- Strip namespace prefix for convenience
        local local_name = name:match(":(.+)$") or name
        if child._text then
            fields[local_name] = child._text
        elseif #child._children == 0 then
            fields[local_name] = ""
        else
            fields[local_name] = XmlParser.extract_fields(child)
        end
    end
    return fields
end

