local SoapGateway = {}
SoapGateway.__index = SoapGateway

-- Extract SOAP Envelope components
function SoapGateway.parse_soap_request(xml_string)
    local doc, err = XmlParser.parse(xml_string)
    if not doc then
        return nil, "XML parse error: " .. (err or "unknown")
    end

    local result = {
        envelope = doc,
        header = nil,
        body = nil,
        action = nil,
        action_params = nil,
        namespace = nil,
    }

    -- Find SOAP Envelope (handle various namespace prefixes)
    local envelope = doc
    local envelope_name = envelope._name or ""
    local is_envelope = envelope_name:match("[Ee]nvelope$")
    if not is_envelope then
        return nil, "Root element is not a SOAP Envelope: " .. envelope_name
    end

    -- Extract SOAP namespace from attributes
    if envelope._attrs then
        for attr_name, attr_value in pairs(envelope._attrs) do
            if attr_value:match("schemas%.xmlsoap%.org") or
               attr_value:match("www%.w3%.org.-soap") then
                result.namespace = attr_value
            end
        end
    end

    -- Find Header (optional)
    result.header = XmlParser.find_descendant(envelope, "Header")

    -- Find Body (required)
    result.body = XmlParser.find_descendant(envelope, "Body")
    if not result.body then
        return nil, "SOAP Body not found in envelope"
    end

    -- Extract the action (first child of Body)
    if result.body._children and #result.body._children > 0 then
        local action_node = result.body._children[1]
        result.action = action_node._name
        -- Strip namespace prefix from action name
        local local_action = result.action:match(":(.+)$")
        if local_action then
            result.action = local_action
        end
        -- Extract parameters as flat fields
        result.action_params = XmlParser.extract_fields(action_node)
        result.action_node = action_node
    end

    -- Extract SOAP headers if present
    if result.header and result.header._children then
        result.header_fields = XmlParser.extract_fields(result.header)
    end

    return result, nil
end

-- Build a simple SOAP fault response
function SoapGateway.build_fault(fault_code, fault_string, detail)
    local detail_xml = ""
    if detail then
        detail_xml = string.format("<detail><message>%s</message></detail>",
            detail:gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;"))
    end
    return string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="http://schemas.xmlsoap.org/soap/envelope/">
  <soap:Body>
    <soap:Fault>
      <faultcode>%s</faultcode>
      <faultstring>%s</faultstring>
      %s
    </soap:Fault>
  </soap:Body>
</soap:Envelope>]],
        fault_code or "soap:Server",
        (fault_string or "Internal Server Error"):gsub("&", "&amp;"):gsub("<", "&lt;"):gsub(">", "&gt;"),
        detail_xml)
end

-- Build a simple SOAP response envelope wrapping a body content string
function SoapGateway.build_response(body_content, namespace)
    namespace = namespace or "http://schemas.xmlsoap.org/soap/envelope/"
    return string.format([[<?xml version="1.0" encoding="UTF-8"?>
<soap:Envelope xmlns:soap="%s">
  <soap:Body>
    %s
  </soap:Body>
</soap:Envelope>]], namespace, body_content)
end

