local function handle_request()
    -- Read the request body
    ngx.req.read_body()
    local body = ngx.req.get_body_data()

    if not body then
        -- Body might be in a temp file
        local body_file = ngx.req.get_body_file()
        if body_file then
            local fh, err = io.open(body_file, "r")
            if fh then
                body = fh:read("*a")
                fh:close()
            else
                ngx.status = 400
                ngx.header["Content-Type"] = "text/xml; charset=utf-8"
                ngx.say(SoapGateway.build_fault("soap:Client", "Unable to read request body", err))
                return ngx.exit(400)
            end
        end
    end

    if not body or body == "" then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(SoapGateway.build_fault("soap:Client", "Empty request body"))
        return ngx.exit(400)
    end

    -- Validate content type
    local content_type = ngx.req.get_headers()["Content-Type"] or ""
    if not content_type:match("text/xml") and not content_type:match("application/soap%+xml") then
        ngx.log(ngx.WARN, "Unexpected Content-Type: ", content_type, " -- proceeding anyway")
    end

    -- Parse the SOAP request
    local soap_req, parse_err = SoapGateway.parse_soap_request(body)
    if not soap_req then
        ngx.status = 400
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(SoapGateway.build_fault("soap:Client", "Invalid SOAP request", parse_err))
        return ngx.exit(400)
    end

    -- Log parsed action for debugging
    ngx.log(ngx.INFO, "SOAP Action: ", soap_req.action or "unknown")
    if soap_req.action_params then
        ngx.log(ngx.INFO, "SOAP Params: ", cjson.encode(soap_req.action_params))
    end

    -- Extract SOAPAction header (commonly used in SOAP 1.1)
    local soap_action_header = ngx.req.get_headers()["SOAPAction"]
    if soap_action_header then
        -- Remove quotes if present
        soap_action_header = soap_action_header:gsub('^"(.*)"$', "%1")
        ngx.log(ngx.INFO, "SOAPAction Header: ", soap_action_header)
    end

    -- Route based on SOAP action
    local action = soap_req.action
    local params = soap_req.action_params or {}
    local response_body = nil

    ---------------------------------------------------------------
    -- Example action handlers - replace with your actual logic
    ---------------------------------------------------------------

    if action == "GetUser" then
        local user_id = params["UserId"] or params["userId"] or "unknown"
        response_body = string.format([[
    <GetUserResponse xmlns="http://example.com/api">
      <UserId>%s</UserId>
      <UserName>John Doe</UserName>
      <Email>john.doe@example.com</Email>
      <Status>Active</Status>
    </GetUserResponse>]], user_id)

    elseif action == "CreateOrder" then
        local product = params["ProductName"] or "Unknown"
        local quantity = params["Quantity"] or "0"
        local customer_id = params["CustomerId"] or "unknown"
        response_body = string.format([[
    <CreateOrderResponse xmlns="http://example.com/api">
      <OrderId>ORD-%s</OrderId>
      <CustomerId>%s</CustomerId>
      <ProductName>%s</ProductName>
      <Quantity>%s</Quantity>
      <Status>Created</Status>
      <Timestamp>%s</Timestamp>
    </CreateOrderResponse>]],
            ngx.now() * 1000,
            customer_id,
            product:gsub("&", "&amp;"):gsub("<", "&lt;"),
            quantity,
            ngx.utctime())

    elseif action == "Ping" then
        response_body = [[
    <PingResponse xmlns="http://example.com/api">
      <Status>OK</Status>
      <Message>SOAP API Gateway is running</Message>
    </PingResponse>]]

    elseif action == "ListServices" then
        response_body = [[
    <ListServicesResponse xmlns="http://example.com/api">
      <Service>
        <Name>GetUser</Name>
        <Description>Retrieve user information by ID</Description>
      </Service>
      <Service>
        <Name>CreateOrder</Name>
        <Description>Create a new order</Description>
      </Service>
      <Service>
        <Name>Ping</Name>
        <Description>Health check endpoint</Description>
      </Service>
      <Service>
        <Name>ListServices</Name>
        <Description>List available SOAP services</Description>
      </Service>
    </ListServicesResponse>]]

    else
        -- Unknown action
        ngx.status = 500
        ngx.header["Content-Type"] = "text/xml; charset=utf-8"
        ngx.say(SoapGateway.build_fault(
            "soap:Client",
            "Unknown SOAP action",
            "The action '" .. (action or "nil") .. "' is not supported by this gateway"
        ))
        return ngx.exit(500)
    end

    -- Send SOAP response
    ngx.status = 200
    ngx.header["Content-Type"] = "text/xml; charset=utf-8"
    local response = SoapGateway.build_response(response_body, soap_req.namespace)
    ngx.say(response)
    return ngx.exit(200)
end

